def sha256_file(path:Path)->str:
    h=hashlib.sha256()
    with path.open('rb') as f:
        for chunk in iter(lambda:f.read(65536),b''):h.update(chunk)
    return h.hexdigest()
def read(path:Path)->str:return path.read_text(encoding='utf-8',errors='ignore')
def write(path:Path,text:str):path.parent.mkdir(parents=True,exist_ok=True);path.write_text(text,encoding='utf-8')
def copy_missing(src_root:Path,dst_root:Path):
    copied=[]
    if not src_root.exists():return copied
    for src in src_root.rglob('*'):
        if src.is_file():
            rel=src.relative_to(src_root);dst=dst_root/rel
            if not dst.exists():
                dst.parent.mkdir(parents=True,exist_ok=True);shutil.copy2(src,dst);copied.append(str(rel))
    return copied
