broken=[]
for p in pages:
    full=PUBLIC/p['url'];txt=read(full)
    for href in re.findall(r"href=[\\\"']([^\\\"']+)[\\\"']", txt, flags=re.I):
        if href.startswith(('http://','https://','mailto:','#','javascript:')) or href.startswith('data:'):continue
        href=href.split('#')[0].split('?')[0]
        if not href or href.endswith('/'):continue
        target=(full.parent/href).resolve()
        try:target.relative_to(PUBLIC.resolve())
        except ValueError:broken.append({'page':p['url'],'href':href,'reason':'escapes public root'});continue
        if not target.exists():broken.append({'page':p['url'],'href':href,'reason':'missing local target'})
